function getYouTubeId(url:string){const m=url?.match(/(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/)|youtu\.be\/)([^&\s?]+)/);return m?m[1]:null;}

// ═══ STANDALONE COMPONENTS ═══
const StableInput=memo(function StableInput({label,value,onChange,type='text',area=false,placeholder=''}:{label:string;value:string;onChange:(v:string)=>void;type?:string;area?:boolean;placeholder?:string;}){
  return(<div className="mb-3"><label className="text-[11px] font-medium block mb-1.5" style={{color:'var(--text-sec)'}}>{label}</label>
    {area?<textarea value={value} onChange={e=>onChange(e.target.value)} rows={3} placeholder={placeholder} className="w-full px-4 py-3 rounded-xl text-[13px]" style={{background:'var(--input-bg)',border:'1px solid var(--input-border)',color:'var(--text)',fontFamily:'DM Sans',resize:'vertical'}}/>
    :<input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} className="w-full px-4 py-3 rounded-xl text-[13px]" style={{background:'var(--input-bg)',border:'1px solid var(--input-border)',color:'var(--text)',fontFamily:'DM Sans'}}/>}
  </div>);
});

function AdminCrudPanel({table,fields,items,title,showPhoto=false,showVideo=false,onSave,onDelete}:{table:string;fields:{key:string;label:string;type?:string;area?:boolean}[];items:any[];title:string;showPhoto?:boolean;showVideo?:boolean;onSave:(t:string,f:any,p:File|null)=>Promise<string>;onDelete:(t:string,id:string)=>Promise<string>;}){
  const [form,setForm]=useState<any>({});const [editId,setEditId]=useState<string|null>(null);const [msg,setMsg]=useState('');const [photoFile,setPhotoFile]=useState<File|null>(null);const [photoPreview,setPhotoPreview]=useState('');const formRef=useRef<HTMLDivElement>(null);
  const handleSave=async()=>{setMsg('');const r=await onSave(table,editId?{...form,_editId:editId}:form,photoFile);setMsg(r);if(r.startsWith('✅')){setForm({});setEditId(null);setPhotoFile(null);setPhotoPreview('');}};
  const startEdit=(item:any)=>{const obj:any={};fields.forEach(f=>{obj[f.key]=item[f.key]||'';});if(item.photo_url)obj.photo_url=item.photo_url;if(item.video_url)obj.video_url=item.video_url;setForm(obj);setEditId(item.id);setMsg('');setPhotoPreview('');setTimeout(()=>{formRef.current?.scrollIntoView({behavior:'smooth',block:'start'});},50);};
  const handlePhoto=(e:ChangeEvent<HTMLInputElement>)=>{const file=e.target.files?.[0];if(file){setPhotoFile(file);const r=new FileReader();r.onloadend=()=>setPhotoPreview(r.result as string);r.readAsDataURL(file);}};
  return(<div>
    <div className="flex justify-between items-center mb-5 flex-wrap gap-3"><h2 className="text-[26px]" style={{fontFamily:'Playfair Display',color:'var(--text)'}}>{title}</h2><button onClick={()=>{setForm({});setEditId(null);setPhotoFile(null);setPhotoPreview('');setMsg('');}} className="btn-gold !py-2 !px-4 !text-[12px]"><Plus size={13}/> Добавить</button></div>
    {msg&&<div className="mb-4 p-3 rounded-xl text-[13px]" style={{background:msg.startsWith('✅')?'rgba(26,125,86,0.08)':'rgba(239,68,68,0.08)',border:`1px solid ${msg.startsWith('✅')?'rgba(26,125,86,0.2)':'rgba(239,68,68,0.2)'}`,color:msg.startsWith('✅')?'var(--accent)':'#ef4444'}}>{msg}</div>}
    <div ref={formRef} className="rounded-xl p-5 mb-6" style={{background:'var(--surface2)',border:'1px solid var(--border)'}}>
      <p className="text-[13px] font-semibold mb-3" style={{color:'var(--gold)'}}>{editId?'✏️ Редактирование':'➕ Новая запись'}</p>
      {fields.map(f=><StableInput key={f.key} label={f.label} value={form[f.key]||''} onChange={v=>setForm((p:any)=>({...p,[f.key]:v}))} type={f.type} area={f.area}/>)}
      {showPhoto&&<div className="mb-3"><label className="text-[11px] font-medium block mb-1.5" style={{color:'var(--text-sec)'}}>Фото</label><div className="flex items-center gap-3"><label className="px-4 py-2 rounded-xl text-[12px] cursor-pointer flex items-center gap-2" style={{background:'var(--gold-bg)',border:'1px solid var(--border)',color:'var(--gold)'}}><Upload size={14}/> Фото<input type="file" accept="image/*" onChange={handlePhoto} className="hidden"/></label>{(photoPreview||form.photo_url)&&<img src={photoPreview||form.photo_url} className="w-12 h-12 rounded-full object-cover"/>}</div></div>}
      {showVideo&&<StableInput label="YouTube видео" value={form.video_url||''} onChange={v=>setForm((p:any)=>({...p,video_url:v}))} placeholder="https://youtube.com/watch?v=..."/>}
      <div className="flex gap-2 mt-2"><button onClick={handleSave} className="btn-gold !py-2 !px-5 !text-[12px]"><Save size={13}/> Сохранить</button>{editId&&<button onClick={()=>{setForm({});setEditId(null);}} className="btn-outline !py-2 !px-4 !text-[12px]">Отмена</button>}</div>
    </div>
    <div className="flex flex-col gap-2">{items.map((it:any)=>(<div key={it.id} className="flex items-center justify-between p-4 rounded-xl" style={{background:'var(--surface)',border:'1px solid var(--border)'}}><div className="flex items-center gap-3 flex-1 min-w-0">{showPhoto&&it.photo_url&&<img src={it.photo_url} className="w-10 h-10 rounded-full object-cover shrink-0"/>}<div className="min-w-0"><p className="text-[14px] font-medium truncate" style={{color:'var(--text)'}}>{it.name||it.title||it.text?.slice(0,50)}</p><p className="text-[11px]" style={{color:'var(--text-sec)'}}>{it.city||it.topic||it.post_type||(it.rating?`${it.rating}⭐`:'')}</p></div></div><div className="flex gap-1.5 shrink-0 ml-3"><button onClick={()=>startEdit(it)} className="w-8 h-8 rounded-lg flex items-center justify-center cursor-pointer" style={{background:'rgba(124,92,224,0.08)',border:'1px solid rgba(124,92,224,0.2)',color:'var(--accent2)'}}><Edit size={13}/></button><button onClick={async()=>{const r=await onDelete(table,it.id);setMsg(r);}} className="w-8 h-8 rounded-lg flex items-center justify-center cursor-pointer" style={{background:'rgba(239,68,68,0.06)',border:'1px solid rgba(239,68,68,0.15)',color:'#ef4444'}}><Trash2 size={13}/></button></div></div>))}{items.length===0&&<p className="text-center py-8 text-[13px]" style={{color:'var(--text-sec)'}}>Пока нет записей</p>}</div>
  </div>);
}

function Section({children,className=''}:{children:React.ReactNode;className?:string}){const ref=useRef<HTMLDivElement>(null);const done=useRef(false);useEffect(()=>{const el=ref.current;if(!el)return;const obs=new IntersectionObserver(([e])=>{if(e.isIntersecting&&!done.current){done.current=true;el.classList.add('vis');obs.unobserve(el);}},{threshold:0.08,rootMargin:'-20px'});obs.observe(el);return()=>obs.disconnect();},[]);return<div ref={ref} className={`reveal-section py-16 px-6 relative z-[2] ${className}`}>{children}</div>;}
function Counter({target}:{target:number}){const[c,setC]=useState(0);const ref=useRef<HTMLSpanElement>(null);const started=useRef(false);useEffect(()=>{const el=ref.current;if(!el)return;const obs=new IntersectionObserver(([e])=>{if(e.isIntersecting&&!started.current){started.current=true;const s=performance.now();const run=(now:number)=>{const p=Math.min((now-s)/2000,1);setC(Math.round((1-Math.pow(1-p,3))*target));if(p<1)requestAnimationFrame(run);};requestAnimationFrame(run);}},{threshold:0.5});obs.observe(el);return()=>obs.disconnect();},[target]);return<span ref={ref}>{c.toLocaleString()}</span>;}
function Particles({dark}:{dark:boolean}){const ref=useRef<HTMLCanvasElement>(null);useEffect(()=>{const c=ref.current;if(!c)return;const ctx=c.getContext('2d')!;const resize=()=>{c.width=window.innerWidth;c.height=window.innerHeight;};resize();window.addEventListener('resize',resize);const rgb=dark?'212,168,83':'184,134,11';const opa=dark?0.2:0.08;const pts=Array.from({length:20},()=>({x:Math.random()*c.width,y:Math.random()*c.height,s:Math.random()*2+0.5,sx:(Math.random()-0.5)*0.2,sy:(Math.random()-0.5)*0.12,o:Math.random()*opa+0.03}));let frame=0;const loop=()=>{ctx.clearRect(0,0,c.width,c.height);pts.forEach(p=>{p.x+=p.sx;p.y+=p.sy;if(p.x<0)p.x=c.width;if(p.x>c.width)p.x=0;if(p.y<0)p.y=c.height;if(p.y>c.height)p.y=0;ctx.beginPath();ctx.arc(p.x,p.y,p.s,0,Math.PI*2);ctx.fillStyle=`rgba(${rgb},${p.o})`;ctx.fill();});frame=requestAnimationFrame(loop);};loop();return()=>{cancelAnimationFrame(frame);window.removeEventListener('resize',resize);};},[dark]);return<canvas ref={ref} className="fixed inset-0 pointer-events-none z-[1]"/>;}
function Title({title,sub}:{title:string;sub?:string}){return(<div className="text-center mb-12"><h2 style={{fontFamily:'Playfair Display',fontSize:'clamp(28px,4.5vw,44px)',fontWeight:600,color:'var(--text)',marginBottom:12}}>{title}</h2><div className="w-20 h-[2px] mx-auto mb-4" style={{background:'linear-gradient(90deg,transparent,var(--gold),transparent)'}}/>{sub&&<p className="text-sm max-w-[550px] mx-auto" style={{color:'var(--text-sec)'}}>{sub}</p>}</div>);}

