// ═══ PRELOADER — Sun & Moon ═══
function Preloader({onDone,dark}:{onDone:()=>void;dark:boolean}){
  const[p,setP]=useState(0);useEffect(()=>{const iv=setInterval(()=>setP(v=>{if(v>=100){clearInterval(iv);setTimeout(onDone,600);return 100;}return v+2;}),40);return()=>clearInterval(iv);},[onDone]);
  const bg=dark?'radial-gradient(ellipse at center,#0F1520 0%,#080C14 70%)':'radial-gradient(ellipse at center,#FFFBF3 0%,#F5ECD8 60%,#EDE0C4 100%)';
  const goldA=dark?'rgba(212,168,83,':'rgba(184,134,11,';const goldS=dark?'#D4A853':'#B8860B';const tC=dark?'rgba(212,168,83,0.5)':'rgba(184,134,11,0.5)';const tC2=dark?'#F0C674':'#B8860B';const barC=dark?'rgba(212,168,83,0.1)':'rgba(184,134,11,0.1)';
  return(<motion.div exit={{opacity:0,scale:1.05}} transition={{duration:0.8}} className="fixed inset-0 z-[10000] flex flex-col items-center justify-center overflow-hidden" style={{background:bg}}>
    <div className="absolute rounded-full" style={{width:500,height:500,background:`radial-gradient(circle,${goldA}0.1),transparent 70%)`,filter:'blur(60px)',animation:'center-breathe 4s ease-in-out infinite',top:'50%',left:'50%',transform:'translate(-50%,-50%)'}}/>
    <div className="absolute" style={{width:350,height:350,top:'50%',left:'50%',animation:'ring-spin 30s linear infinite',transform:'translate(-50%,-50%)'}}>{Array.from({length:16}).map((_,i)=><div key={i} className="absolute" style={{top:'50%',left:'50%',width:1,height:175,marginLeft:-0.5,marginTop:-175,transformOrigin:'bottom center',transform:`rotate(${i*22.5}deg)`,background:`linear-gradient(to top,${goldA}${i%2===0?'0.2':'0.08'}),transparent)`,animation:'ray-pulse 3s ease-in-out infinite',animationDelay:`${i*0.2}s`}}/>)}</div>
    <div className="relative" style={{width:240,height:240}}>
      {[1,2].map(r=><div key={r} className="absolute rounded-full" style={{width:r*80,height:r*80,top:'50%',left:'50%',border:`1px solid ${goldA}0.12)`,animation:`${r%2===0?'ring-spin':'ring-spin-r'} ${8+r*3}s linear infinite`,transform:'translate(-50%,-50%)'}}/>)}
      <motion.div initial={{x:-30,opacity:0,scale:0.5}} animate={{x:0,opacity:1,scale:1}} transition={{delay:0.3,duration:1}} className="absolute" style={{top:'50%',left:'50%',marginTop:-32,marginLeft:-70}}>
        <div className="rounded-full" style={{width:64,height:64,background:`radial-gradient(circle at 35% 35%,#FFF8E1,#FFD54F,${goldS},rgba(184,134,11,0.5))`,boxShadow:`0 0 40px ${goldA}0.4)`,animation:'lotus-glow 3s ease-in-out infinite'}}>{Array.from({length:8}).map((_,i)=><div key={i} className="absolute" style={{top:'50%',left:'50%',width:2,height:14,marginLeft:-1,marginTop:-40,transformOrigin:'center 40px',transform:`rotate(${i*45}deg)`,background:`linear-gradient(to top,${goldA}0.6),transparent)`,borderRadius:2,animation:'ray-pulse 2s ease-in-out infinite',animationDelay:`${i*0.25}s`}}/>)}</div>
      </motion.div>
      <motion.div initial={{x:30,opacity:0,scale:0.5}} animate={{x:0,opacity:1,scale:1}} transition={{delay:0.6,duration:1}} className="absolute" style={{top:'50%',left:'50%',marginTop:-26,marginLeft:18}}>
        <div className="rounded-full relative" style={{width:52,height:52,background:'radial-gradient(circle at 65% 35%,#F5F0E8,#8B7D6B,rgba(139,125,107,0.6))',boxShadow:'0 0 30px rgba(200,190,175,0.2)'}}><div className="absolute rounded-full" style={{width:42,height:42,top:2,left:12,background:dark?'rgba(15,21,32,0.5)':'rgba(245,236,216,0.5)'}}/></div>
      </motion.div>
      <motion.div initial={{opacity:0}} animate={{opacity:1}} transition={{delay:1.2}} className="absolute rounded-full" style={{width:20,height:20,top:'50%',left:'50%',marginTop:-10,marginLeft:-10,background:`radial-gradient(circle,${goldA}0.4),transparent)`,animation:'lotus-glow 2s ease-in-out infinite'}}/>
      {Array.from({length:8}).map((_,i)=>{const a=(i/8)*Math.PI*2;return<div key={i} className="absolute rounded-full" style={{top:`calc(50% + ${Math.sin(a)*90}px)`,left:`calc(50% + ${Math.cos(a)*90}px)`,width:3,height:3,background:goldS,transform:'translate(-50%,-50%)',animation:'dot-pulse 2s ease-in-out infinite',animationDelay:`${i*0.2}s`}}/>;})}</div>
    <div className="mt-10 text-center" style={{animation:'hero-fade 0.8s ease forwards',animationDelay:'0.5s',opacity:0}}><p className="text-[10px] tracking-[4px] uppercase mb-3" style={{color:tC}}>РОЭНЦ · Казахстан</p><p style={{fontFamily:'Playfair Display',fontSize:26,fontStyle:'italic',color:tC2}}>Исцеление через знание</p></div>
    <div className="mt-8" style={{width:200}}><div className="w-full h-[2px] rounded-full overflow-hidden" style={{background:barC}}><div className="h-full rounded-full" style={{width:`${p}%`,background:`linear-gradient(90deg,${goldS},var(--accent,#1A7D56))`,transition:'width 0.1s'}}/></div><p className="text-[10px] text-center mt-2" style={{color:`${goldA}0.4)`}}>{p<100?'Загрузка...':'Добро пожаловать'}</p></div>
  </motion.div>);
}

